changeSet.sql:
DO $$
DECLARE
    grants jsonb := '[
      {"role": "TENANT_ADMIN",    "perms": ["customer:write","payment:write","uom:read","uom:create","lot:read","lot:write","inventory:transfer","inventory:count","reporting:read","expense:write"]},
      {"role": "MANAGER",         "perms": ["customer:write","payment:write","uom:read","uom:create","lot:read","lot:write","inventory:transfer","inventory:count","reporting:read","expense:write"]},
      {"role": "ACCOUNTANT",      "perms": ["reporting:read"]},
      {"role": "PAYMENT_OFFICER", "perms": ["customer:write","payment:write","reporting:read"]},
      {"role": "CASHIER",         "perms": ["customer:write","payment:write","uom:read","lot:read"]},
      {"role": "STOCK_KEEPER",    "perms": ["uom:read","lot:read","lot:write","inventory:transfer","inventory:count"]},
      {"role": "VIEWER",          "perms": ["uom:read","lot:read","reporting:read"]}
    ]'::jsonb;
    entry jsonb;
    rcode text;
    pcodes text[];
BEGIN
    FOR entry IN SELECT * FROM jsonb_array_elements(grants) LOOP
        rcode := entry->>'role';
        SELECT ARRAY(SELECT jsonb_array_elements_text(entry->'perms')) INTO pcodes;

        INSERT INTO role_permission (role_id, permission_id)
        SELECT r.id, p.id
        FROM roles r
        JOIN permissions p ON p.code = ANY(pcodes)
        WHERE r.code = rcode
        ON CONFLICT DO NOTHING;
    END LOOP;
END $$;
